const resp = $input.first().json || {};
const body = (resp.body && typeof resp.body === 'object') ? resp.body : resp;
const statusCode = Number(resp.statusCode ?? 200);
const svc = body.services || {};
const api_status = body.status ?? 'unknown';
const pg = svc.postgres ?? body.postgres ?? 'unknown';
const rd = svc.redis ?? body.redis ?? 'unknown';
const ol = svc.ollama ?? body.ollama ?? 'unknown';

const is_healthy = statusCode === 200 && (api_status === 'ok' || api_status === 'healthy');
const now_iso = new Date().toISOString();

const sd = $getWorkflowStaticData('global');
const history = Array.isArray(sd.history) ? sd.history.slice() : [];
history.push({ ts: now_iso, healthy: is_healthy, statusCode, api_status, postgres: pg, redis: rd, ollama: ol });
while (history.length > 96) history.shift();  // ~24h at 15m
sd.history = history;

// Last known good
let last_good = null;
for (let i = history.length - 1; i >= 0; i--) {
  if (history[i].healthy && history[i].ts !== now_iso) { last_good = history[i].ts; break; }
}

// Service regression
const prev = history.length >= 2 ? history[history.length - 2] : null;
const regressed = [];
if (prev) {
  if (prev.postgres === 'ok' && pg !== 'ok') regressed.push('postgres');
  if (prev.redis === 'ok' && rd !== 'ok') regressed.push('redis');
  if (prev.ollama === 'ok' && ol !== 'ok') regressed.push('ollama');
}

// Flap detection over last hour (4 entries)
const window = history.slice(-4);
let transitions = 0;
for (let i = 1; i < window.length; i++) {
  if (window[i].healthy !== window[i - 1].healthy) transitions += 1;
}
const flapping = transitions >= 3;

const failed_services = [
  pg !== 'ok' ? 'postgres' : null,
  rd !== 'ok' ? 'redis' : null,
  ol !== 'ok' ? 'ollama' : null,
].filter(Boolean);
if (!is_healthy && failed_services.length === 0) failed_services.push('api_unreachable');

const alert_required = (!is_healthy) || flapping;
const severity = !is_healthy ? 'critical' : (flapping ? 'warning' : 'info');

const slackPrefix = !is_healthy ? ':red_circle: *ModelForge Health FAILED*' : ':warning: *ModelForge Health Flapping*';
const slack_message = [
  slackPrefix,
  `\u2022 Time: \`${now_iso}\``,
  `\u2022 HTTP: \`${statusCode}\` | API: \`${api_status}\``,
  `\u2022 Postgres: \`${pg}\` | Redis: \`${rd}\` | Ollama: \`${ol}\``,
  `\u2022 Failed: \`${failed_services.join(', ') || 'none'}\``,
  regressed.length ? `\u2022 Regressed since last check: \`${regressed.join(', ')}\`` : null,
  flapping ? `\u2022 Flapping: ${transitions} transitions in last hour` : null,
  `\u2022 Last known good: \`${last_good ?? 'none in window'}\``,
].filter(Boolean).join('\n');

console.log('[health] sample', { is_healthy, flapping, transitions, regressed, failed_services });

return [{
  json: {
    is_healthy,
    flapping,
    transitions,
    alert_required,
    severity,
    statusCode,
    api_status,
    postgres: pg,
    redis: rd,
    ollama: ol,
    failed_services,
    failed_services_csv: failed_services.join(', '),
    regressed,
    regressed_csv: regressed.join(', '),
    last_known_good: last_good,
    history_len: history.length,
    detected_at: now_iso,
    slack_message,
  }
}];
